  browser VARCHAR(300),
  device VARCHAR(200),
  os VARCHAR(200),
  country VARCHAR(100),
  attempt_count INTEGER NOT NULL DEFAULT 1,
  last_attempt_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  blocked_until TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
