  checkin_type VARCHAR(20) NOT NULL DEFAULT 'checkin',
  timestamp TIMESTAMPTZ NOT NULL DEFAULT now(),
  photo_url TEXT,
  latitude DECIMAL(10,7),
  longitude DECIMAL(10,7),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
