-- ============================================================
-- AUTO-UPDATE TRIGGERS
-- ============================================================
CREATE TRIGGER update_accommodation_locations_updated_at BEFORE UPDATE ON accommodation_locations FOR EACH ROW EXECUTE FUNCTION update_updated_at();
