  assigned_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  status duty_status NOT NULL DEFAULT 'scheduled',
  notes TEXT,
  assigned_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ
);
