);
ALTER TABLE inventory_units ENABLE ROW LEVEL SECURITY;

-- ============================================================
-- 7. INVENTORY STOCK
-- ============================================================
CREATE TABLE inventory_stock (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
