  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(item_id, warehouse_id, location_id, batch_number)
);
ALTER TABLE inventory_stock ENABLE ROW LEVEL SECURITY;

