CREATE OR REPLACE FUNCTION update_devops_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER update_deploy_envs_updated_at BEFORE UPDATE ON deployment_environments FOR EACH ROW EXECUTE FUNCTION update_devops_updated_at();
